const plegMaxParallelism = 16

func (g *GenericPLEG) Relist(ctx context.Context) {
	// ... existing code ...

	type podWork struct {
		podUID types.UID
		pod    *kubecontainer.Pod
		events []*PodLifecycleEvent
	}

	var workList []podWork
